// app/layout.tsx
import type { Metadata } from 'next';

export const metadata: Metadata = {
  title: 'Admin — Product Catalog',
  description: 'Admin product catalog with cache-tag-based invalidation',
};

export default function RootLayout({
  children
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en">
      <body>{children}</body>
    </html>
  );
}


// lib/db.js
let catalogData = [
  { id: 1, name: 'Laptop', price: 999, stock: 42, status: 'active' },
  { id: 2, name: 'Phone', price: 699, stock: 138, status: 'active' },
  { id: 3, name: 'Tablet', price: 499, stock: 27, status: 'active' },
  { id: 4, name: 'Headphones', price: 199, stock: 310, status: 'active' },
  { id: 5, name: 'Watch', price: 299, stock: 5, status: 'low-stock' },
];

export async function getAllProducts() {
  // Simulate database read delay
  await new Promise(resolve => setTimeout(resolve, 100));
  return catalogData;
}

/**
 * Simulates a full sync from an upstream ERP/PIM system.
 * In production this would batch-fetch pricing, inventory, and availability
 * from an external source.  The caller is expected to revalidate any stale
 * cache tags after the sync completes.
 */
export async function syncCatalogFromUpstream() {
  // Simulate network / processing delay for a "thousands of SKUs" sync
  await new Promise(resolve => setTimeout(resolve, 2_000));

  // Perturb stock levels to demonstrate that data actually changed
  catalogData = catalogData.map((p) => {
    const newStock = Math.max(0, p.stock + Math.floor((Math.random() - 0.5) * 20));
    return { ...p, stock: newStock, status: newStock > 10 ? 'active' : 'low-stock' };
  });

  return { syncedAt: new Date().toISOString(), count: catalogData.length };
}

// app/page.tsx
export default function Page() {
  return (
    <div>
      <h1>Home</h1>
    </div>
  );
}


